export const DevOnlyPlugin = () => createUnplugin(() => {
  return {
    name: 'nuxt:server-devonly:transform',
    enforce: 'pre',
    transformInclude (id) {
      return isVue(id, { type: ['template'] })
    },
    transform: {
      filter: {
        code: { include: DEVONLY_COMP_SINGLE_RE },
      },
      handler (code, id, meta?: unknown) {
        const s = rolldownString(code, id, meta)
        for (const match of code.matchAll(DEVONLY_COMP_RE)) {
          const ast: Node = parse(match[0]).children[0]
          const fallback: Node | undefined = ast.children?.find((n: Node) => {
            if (n.name !== 'template') { return false }
            return 'fallback' in n.attributes || '#fallback' in n.attributes || 'v-slot:fallback' in n.attributes
          })
          const replacement = fallback ? match[0].slice(fallback.loc[0].end, fallback.loc.at(-1).start) : ''
          s.overwrite(match.index!, match.index! + match[0].length, replacement)
        }

        return generateTransform(s, id)
      },
    },
  }
})

export const NuxtRootStubPlugin = (options: NuxtRootStubPluginOptions): Plugin => {
  const extension = extname(options.entry)
  const escapedExt = extension.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
  const entryPath = join(dirname(options.entry), STUB_ID + extension)
  const idFilter = new RegExp(`${STUB_ID}(?:${escapedExt})?$`)

  return {
    name: PLUGIN_NAME,
    enforce: 'pre',
    resolveId: {
      filter: {
        id: idFilter,
      },
      async handler(id, importer) {
        return importer?.endsWith('index.html') ? id : entryPath
      },
    },
    load: {
      filter: {
        id: idFilter,
      },
      async handler() {
        const entryContents = readFileSync(options.entry, 'utf-8')
        return entryContents.replace('#build/root-component.mjs', options.rootStubPath)
      },
    },
  }
}

for (const [source, apis] of Object.entries(AUTO_IMPORTS)) {
  const alreadyImported = existingImports.get(source) ?? new Set()
  const needed: string[] = []

  for (const api of apis) {
    if (alreadyImported.has(api)) continue

    const pattern = new RegExp(`\\b${api}\\b(?!\\s*:)`)
    if (pattern.test(scriptContent)) {
      needed.push(api)
    }
  }

  if (!needed.length) continue

  if (alreadyImported.size) {
    const merged = [...alreadyImported, ...needed]
    const mergedImport = `import { ${merged.join(', ')} } from '${source}'`
    const existingPattern = new RegExp(`import\\s+\\{[^}]+\\}\\s+from\\s+['"]${source.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}['"]`)
    code = code.replace(existingPattern, mergedImport)
  } else {
    newImports.push({ source, names: needed })
  }
}

const CAST_TEMPLATES: Record<string, (raw: any) => string> = {
  'DateValue': (raw) => {
    if (!raw || !Array.isArray(raw)) return 'null'
    const [y, m, d] = raw
    return `new CalendarDate(${y}, ${m}, ${d})`
  },
  'DateValue[]': (raw) => {
    if (!Array.isArray(raw)) return '[]'
    return `[${raw.map(([y, m, d]: number[]) => `new CalendarDate(${y}, ${m}, ${d})`).join(', ')}]`
  },
  'DateRange': (raw) => {
    if (!raw?.start || !raw?.end) return '{ start: null, end: null }'
    const [sy, sm, sd] = raw.start
    const [ey, em, ed] = raw.end
    return `{ start: new CalendarDate(${sy}, ${sm}, ${sd}), end: new CalendarDate(${ey}, ${em}, ${ed}) }`
  },
  'TimeValue': (raw) => {
    if (!raw || !Array.isArray(raw)) return 'null'
    const [h, m, s] = raw
    return `new Time(${h}, ${m}, ${s})`
  },
  'TimeRangeValue': (raw) => {
    if (!raw?.start || !raw?.end) return 'null'
    const [sh, sm, ss] = raw.start
    const [eh, em, es] = raw.end
    return `{ start: new Time(${sh}, ${sm}, ${ss}), end: new Time(${eh}, ${em}, ${es}) }`
  }
}

