const slots = Object.entries(slotNodes).reduce((slots, [name, { props, children }]) => {
    if (!children.length) {
      return slots
    }

    slots[name] = (data = {}) => {
      const scopedProps = pick(data, Object.keys(props || {}))
      let vNodes = children.map((child, index) => {
        return _renderNode(
          child,
          h,
          {
            documentMeta,
            parentScope: { ...parentScope, ...scopedProps },
            resolveComponent,
          },
          String((child as MDCElement).props?.key || index),
        )
      })

      if (props?.unwrap) {
        vNodes = flatUnwrap(vNodes, props.unwrap) as VNode[]
      }
      return mergeTextNodes(vNodes)
    }

    return slots
  }, {} as Record<string, (data?: Record<string, any>) => VNode[]>)

nuxt.hook('ready', () => {
  const nitro = useNitro()
  const _addWasmSupport = (_nitro: typeof nitro) => {
    if (nitro.options.experimental?.wasm) {
      return
    }
    _nitro.options.externals = _nitro.options.externals || {}
    _nitro.options.externals.inline = _nitro.options.externals.inline || []
    _nitro.options.externals.inline.push(id => id.endsWith('.wasm'))
    _nitro.hooks.hook('rollup:before', async (_, rollupConfig) => {
      const { rollup: unwasm } = await import('unwasm/plugin')
      rollupConfig.plugins = rollupConfig.plugins || []
      ;(rollupConfig.plugins as any[]).push(
        unwasm({
          ...(_nitro.options.wasm as any),
        }),
      )
    })
  }
  _addWasmSupport(nitro)
  nitro.hooks.hook('prerender:init', (prerenderer) => {
    _addWasmSupport(prerenderer)
  })
})

