if (!cookie.secure) {
  // CHIPS: Partitioned requires Secure
  if (cookie.partitioned) {
    throw new TypeError(`Partitioned cookies must have the Secure attribute`);
  }
  // RFC 6265bis sec 4.1.2.7: SameSite=None requires Secure
  if (cookie.sameSite && String(cookie.sameSite).toLowerCase() === "none") {
    throw new TypeError(`SameSite=None cookies must have the Secure attribute`);
  }
  // RFC 6265bis sec 4.1.3: __Secure- prefix requires Secure
  if (
    cookie.name.length > 9 &&
    cookie.name.charCodeAt(0) === 95 /* _ */ &&
    cookie.name.charCodeAt(1) === 95 /* _ */
  ) {
    const nameLower = cookie.name.toLowerCase();
    if (nameLower.startsWith("__secure-") || nameLower.startsWith("__host-")) {
      throw new TypeError(`${cookie.name} cookies must have the Secure attribute`);
    }
  }
}

export const github: TemplateProvider = (input, options) => {
  const parsed = parseGitURI(input);

  // https://docs.github.com/en/rest/repos/contents#download-a-repository-archive-tar
  // TODO: Verify solution for github enterprise
  const githubAPIURL = process.env.GIGET_GITHUB_URL || "https://api.github.com";

  return {
    name: parsed.repo.replace("/", "-"),
    version: parsed.ref,
    subdir: parsed.subdir,
    headers: {
      Authorization: options.auth ? `Bearer ${options.auth}` : undefined,
      Accept: "application/vnd.github+json",
      "X-GitHub-Api-Version": "2022-11-28",
    },
    url: `${githubAPIURL.replace("api.github.com", "github.com")}/${
      parsed.repo
    }/tree/${parsed.ref}${parsed.subdir}`,
    tar: `${githubAPIURL}/repos/${parsed.repo}/tarball/${parsed.ref}`,
  };
};

return (...args: any[]) => {
  let tempFile: string | undefined;
  const importViaTempFile = () => {
    tempFile = writeEsmTempFile(wrapped, filename);
    debug(ctx, "[esm]", "[tempfile]", tempFile);
    return nativeImport(pathToFileURL(tempFile));
  };
  const modPromise = uri
    ? nativeImport(uri).catch((error: any) => {
        // Fallback to temp file on ENAMETOOLONG (encrypted home dirs /
        // strict NAME_MAX filesystems).
        if (error?.code !== "ENAMETOOLONG") {
          throw error;
        }
        return importViaTempFile();
      })
    : importViaTempFile();
  return modPromise
    .then((mod) => mod.default(...args))
    .finally(() => {
      if (tempFile) {
        unlink(tempFile).catch(() => {});
      }
    });
};

for (const setCookieStr of setCookieHeader) {
  const setCookie = Object.entries(parse(setCookieStr));
  if (setCookie.length === 0) {
    continue;
  }
  const [[key, value], ..._setCookieOptions] = setCookie;
  const setCookieOptions = Object.fromEntries(
    _setCookieOptions.map(([k, v]) => [k.toLowerCase(), v])
  );
  const cookieObject: Cookie = {
    name: key,
    value: value || "",
    domain: setCookieOptions.domain,
    path: setCookieOptions.path,
    expires: parseNumberOrDate(setCookieOptions.expires || ""),
    sameSite: setCookieOptions.samesite as "Lax" | "Strict" | "None",
    maxAge: parseNumber(setCookieOptions["max-age"] || ""),
    secure: setCookieStr.includes("Secure") ? true : undefined,
    httpOnly: setCookieStr.includes("HttpOnly") ? true : undefined,
  };
  azureCookies.push(cookieObject);
}

const handler = async (req: ServerRequest): Promise<Response> => {
  req.runtime ??= { name: "netlify" };
  req.ip ??= req.headers.get("x-nf-client-connection-ip") || undefined;

  const response = await nitroApp.fetch(req);

  const isr = (req.context?.routeRules || {})?.isr?.options;
  if (isr) {
    const maxAge = typeof isr === "number" ? isr : ONE_YEAR_IN_SECONDS;
    const revalidateDirective =
      typeof isr === "number" ? `stale-while-revalidate=${ONE_YEAR_IN_SECONDS}` : "must-revalidate";
    if (!response.headers.has("Cache-Control")) {
      response.headers.set("Cache-Control", "public, max-age=0, must-revalidate");
    }
    response.headers.set(
      "Netlify-CDN-Cache-Control",
      `public, max-age=${maxAge}, ${revalidateDirective}, durable`
    );
  }

  return response;
};

export const relative: typeof path.relative = function (from, to) {
  // we cast these because `split` will always be at least one string
  const _from = resolve(from).replace(_ROOT_FOLDER_RE, "$1").split("/") as [
    string,
    ...string[],
  ];
  const _to = resolve(to).replace(_ROOT_FOLDER_RE, "$1").split("/") as [
    string,
    ...string[],
  ];

  // Different windows drive letters
  if (_to[0][1] === ":" && _from[0][1] === ":" && _from[0] !== _to[0]) {
    return _to.join("/");
  }

  const _fromCopy = [..._from];
  for (const segment of _fromCopy) {
    if (_to[0] !== segment) {
      break;
    }
    _from.shift();
    _to.shift();
  }
  return [..._from.map(() => ".."), ..._to].join("/");
};

